mapper.select:
SELECT ar.area_code as district_code, ar.area_name as district_name, COUNT(DISTINCT p.institution_id) as institution_count, COALESCE(SUM(ai.total_balance), 0) as total_fund, COALESCE(SUM(ai.service_balance), 0) as service_balance, COALESCE(SUM(ai.deposit_balance), 0) as deposit_balance, COALESCE(SUM(ai.member_balance), 0) as member_balance, COALESCE(COUNT(DISTINCT ai.elder_id), 0) as elder_count FROM area_street ar LEFT JOIN pension_institution p ON p.area_code COLLATE utf8mb4_general_ci = ar.area_code COLLATE utf8mb4_general_ci LEFT JOIN account_info ai ON ai.institution_id = p.institution_id WHERE ar.area_name IS NOT NULL
AND ar.area_code COLLATE utf8mb4_general_ci = #{districtCode}
GROUP BY ar.area_code, ar.area_name ORDER BY MIN(ar.sort_order)

SELECT e.elder_id, e.elder_name, e.gender, e.id_card, e.age, e.phone, e.health_status, e.care_level, e.status as elder_status, ar.area_name as district_name, p.institution_id, p.institution_name, ai.total_balance, ai.service_balance, ai.deposit_balance, ai.member_balance FROM elder_info e INNER JOIN account_info ai ON ai.elder_id = e.elder_id INNER JOIN pension_institution p ON p.institution_id = ai.institution_id LEFT JOIN (SELECT DISTINCT area_code, area_name FROM area_street WHERE area_name IS NOT NULL) ar ON p.area_code COLLATE utf8mb4_general_ci = ar.area_code COLLATE utf8mb4_general_ci WHERE 1=1
AND p.area_code COLLATE utf8mb4_general_ci = #{districtCode}
AND e.elder_name LIKE CONCAT('%', #{elderName}, '%')
AND p.institution_id = #{institutionId}
GROUP BY e.elder_id, e.elder_name, e.gender, e.id_card, e.age, e.phone, e.health_status, e.care_level, e.status, ar.area_name, p.institution_id, p.institution_name, ai.total_balance, ai.service_balance, ai.deposit_balance, ai.member_balance ORDER BY MIN(ai.create_time) DESC
